import pytest
import requests

def test_create_encounter_valid_start_before_end(base_url, clinician_auth_token, existing_patient_id):
    payload = {
        "resourceType": "Encounter",
        "status": "finished",
        "subject": {"reference": f"Patient/{existing_patient_id}"},
        "period": {
            "start": "2024-06-01T08:00:00Z",
            "end":   "2024-06-01T09:00:00Z"
        }
    }
    headers = {"Authorization": f"Bearer {clinician_auth_token}", "Content-Type": "application/fhir+json"}
    resp = requests.post(f"{base_url}/Encounter", json=payload, headers=headers)
    assert resp.status_code == 201, f"Expected 201, got {resp.status_code}: {resp.text}"
    body = resp.json()
    assert body.get("resourceType") == "Encounter"
    assert "id" in body
    assert body["period"]["start"] == "2024-06-01T08:00:00Z"
    assert body["period"]["end"]   == "2024-06-01T09:00:00Z"

import pytest
import requests

def test_create_encounter_end_before_start_rejected(base_url, clinician_auth_token, existing_patient_id):
    payload = {
        "resourceType": "Encounter",
        "status": "finished",
        "subject": {"reference": f"Patient/{existing_patient_id}"},
        "period": {
            "start": "2024-06-01T10:00:00Z",
            "end":   "2024-06-01T09:00:00Z"
        }
    }
    headers = {"Authorization": f"Bearer {clinician_auth_token}", "Content-Type": "application/fhir+json"}
    resp = requests.post(f"{base_url}/Encounter", json=payload, headers=headers)
    assert resp.status_code == 422, f"Expected 422, got {resp.status_code}: {resp.text}"
    body = resp.json()
    # Accept either FHIR OperationOutcome or generic error key
    has_error = (
        body.get("resourceType") == "OperationOutcome"
        or "error" in body
        or "issue" in body
    )
    assert has_error, f"Expected error body, got: {body}"

import pytest
import requests

def test_create_encounter_end_equals_start_boundary(base_url, clinician_auth_token, existing_patient_id):
    ts = "2024-06-01T08:00:00Z"
    payload = {
        "resourceType": "Encounter",
        "status": "finished",
        "subject": {"reference": f"Patient/{existing_patient_id}"},
        "period": {"start": ts, "end": ts}
    }
    headers = {"Authorization": f"Bearer {clinician_auth_token}", "Content-Type": "application/fhir+json"}
    resp = requests.post(f"{base_url}/Encounter", json=payload, headers=headers)
    assert resp.status_code in (201, 422), (
        f"Expected 201 or 422 for equal timestamps, got {resp.status_code}: {resp.text}"
    )
    body = resp.json()
    if resp.status_code == 201:
        assert "id" in body
        assert body["period"]["start"] == ts
        assert body["period"]["end"]   == ts
    else:
        has_error = (
            body.get("resourceType") == "OperationOutcome"
            or "error" in body
            or "issue" in body
        )
        assert has_error, f"Expected error body for 422, got: {body}"

